+// Tests
+// ============================================================================
+
+test "compression: zstd_get_decompressed_size too short" {
+    const data = [_]u8{ 0x28, 0xB5, 0x2F, 0xFD };
+    const result = zstd_get_decompressed_size(&data, data.len);
+    try std.testing.expectEqual(@as(usize, 0), result);
+}
+
