+pub export fn getStringCount(col_idx: u32) u64 {
+    const buf = getStringBuffer(col_idx) orelse return 0;
+    if (buf.data_size == 0) return 0;
+    return buf.rows;
+}
+
+/// Debug: Get detailed string read info for a specific row
