+    if (buf.rows == 0 or row_idx >= buf.rows) return 0;
+
+    const dim = buf.size / (buf.rows * 4);
+    if (dim == 0) return 0;
+
+    const vec_start = buf.start + @as(usize, row_idx) * dim * 4;
+    const actual_dim = @min(dim, max_dim);
