+pub export fn cosineSimilarity(
+    vec_a: [*]const f32,
+    vec_b: [*]const f32,
+    dim: usize,
+) f32 {
+    var dot: f32 = 0;
+    var norm_a: f32 = 0;
+    var norm_b: f32 = 0;
