+    for (0..dim) |i| {
+        const a = vec_a[i];
+        const b = vec_b[i];
+        dot += a * b;
+        norm_a += a * a;
+        norm_b += b * b;
+    }
+
+    const denom = @sqrt(norm_a) * @sqrt(norm_b);
+    if (denom == 0) return 0;
+    return dot / denom;
+}
